import{_ as a,o as s,c as n,a3 as o}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"目录结构浏览器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/directory-tree.md","filePath":"user-guide/tools/directory-tree.md","lastUpdated":1784173150000}'),e={name:"user-guide/tools/directory-tree.md"};function d(r,t,l,i,p,c){return s(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="目录结构浏览器" tabindex="-1">目录结构浏览器 <a class="header-anchor" href="#目录结构浏览器" aria-label="Permalink to &quot;目录结构浏览器&quot;">​</a></h1><blockquote><p>快速生成目录树结构，支持智能过滤和灵活的二次筛选，让你对项目结构一目了然。</p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>目录结构浏览器帮你<strong>一键生成</strong>清晰、美观的目录树，核心能力包括：</p><ul><li><strong>🌲 树状可视化</strong> — 递归遍历目标目录，生成标准的 ASCII 目录树，文件/目录层级一目了然</li><li><strong>🔍 智能过滤</strong> — 支持 <code>.gitignore</code> 规则、自定义 glob 模式、两者组合三种过滤方式，精准控制展示内容</li><li><strong>⚡ Rust 后端驱动</strong> — 目录遍历和过滤由原生 Rust 后端执行（基于 <code>ignore</code> crate），即使是大项目也能秒级生成</li><li><strong>🎛️ 实时二次筛选</strong> — 生成后无需重新扫描，直接在前端通过深度滑块、包含/排除关键词等控件实时调整视图</li><li><strong>📋 一键导出与复用</strong> — 支持复制到剪贴板、导出为 <code>.txt</code> / <code>.md</code> 文件、直接将树结构发送到 LLM 聊天窗口</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="_1-打开工具" tabindex="-1">1. 打开工具 <a class="header-anchor" href="#_1-打开工具" aria-label="Permalink to &quot;1. 打开工具&quot;">​</a></h3><p>在左侧工具栏中找到 <strong>目录结构浏览器</strong>（图标为 📂），点击进入。</p><h3 id="_2-选择目标目录" tabindex="-1">2. 选择目标目录 <a class="header-anchor" href="#_2-选择目标目录" aria-label="Permalink to &quot;2. 选择目标目录&quot;">​</a></h3><p>点击配置面板中的 <strong>&quot;选择目录&quot;</strong> 按钮，通过系统对话框选取要分析的文件夹。</p><blockquote><p>也可以直接将文件夹从资源管理器<strong>拖拽</strong>到目标路径输入框中，工具会自动填入路径。若开启了&quot;拖拽后自动生成&quot;，松开即开始生成。</p></blockquote><h3 id="_3-生成目录树" tabindex="-1">3. 生成目录树 <a class="header-anchor" href="#_3-生成目录树" aria-label="Permalink to &quot;3. 生成目录树&quot;">​</a></h3><p>点击 <strong>&quot;生成&quot;</strong> 按钮，Rust 后端会快速遍历目录并返回结构化数据。右侧结果面板会立刻展示生成的目录树。</p><p><img src="" alt="TODO: 目录树生成结果截图"></p><h3 id="_4-查看与操作结果" tabindex="-1">4. 查看与操作结果 <a class="header-anchor" href="#_4-查看与操作结果" aria-label="Permalink to &quot;4. 查看与操作结果&quot;">​</a></h3><ul><li><strong>浏览</strong> — 在右侧编辑器中查看完整的目录树，支持语法高亮和行号</li><li><strong>复制</strong> — 点击复制按钮，将当前树结构复制到剪贴板</li><li><strong>导出</strong> — 点击导出按钮，保存为 <code>.txt</code> 或 <code>.md</code> 文件</li><li><strong>发送到聊天</strong> — 点击发送按钮，将树结构直接输入到 LLM 聊天窗口，方便 AI 分析项目结构</li></ul><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="配置面板" tabindex="-1">配置面板 <a class="header-anchor" href="#配置面板" aria-label="Permalink to &quot;配置面板&quot;">​</a></h3><p>左侧配置面板提供了以下参数，决定目录树的<strong>初始生成</strong>行为：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td><strong>目标路径</strong></td><td>要分析的目录路径，可手动输入或通过选择对话框选取</td><td>-</td></tr><tr><td><strong>显示文件</strong></td><td>是否在树中包含文件（关闭后只显示目录结构）</td><td>✅ 开启</td></tr><tr><td><strong>显示隐藏项目</strong></td><td>是否显示名称以 <code>.</code> 开头的隐藏文件和目录</td><td>❌ 关闭</td></tr><tr><td><strong>最大深度</strong></td><td>目录树的最大层级（0 表示无限制，建议保持 5-10 避免过长输出）</td><td><code>5</code></td></tr><tr><td><strong>过滤模式</strong></td><td>选择过滤规则的应用方式：不过滤 / 使用 .gitignore / 自定义规则 / 两者同时使用</td><td>不过滤</td></tr><tr><td><strong>自定义规则</strong></td><td>当过滤模式为&quot;自定义规则&quot;或&quot;两者同时使用&quot;时，在此输入 glob 模式（每行一条）</td><td>内置示例</td></tr></tbody></table><blockquote><p><strong>💡 提示</strong>: 自定义规则支持标准的 glob 模式语法，如 <code>node_modules</code>、<code>*.log</code>、<code>dist</code>。以 <code>#</code> 开头的行会被视为注释。</p></blockquote><h3 id="过滤模式详解" tabindex="-1">过滤模式详解 <a class="header-anchor" href="#过滤模式详解" aria-label="Permalink to &quot;过滤模式详解&quot;">​</a></h3><p>四种过滤模式覆盖了从&quot;完全不过滤&quot;到&quot;双重过滤&quot;的所有场景：</p><table tabindex="0"><thead><tr><th>模式</th><th>适用场景</th><th>示例</th></tr></thead><tbody><tr><td><strong>不过滤</strong></td><td>想看完整的目录结构，不加任何限制</td><td>快速了解项目全貌</td></tr><tr><td><strong>使用 .gitignore</strong></td><td>项目已有 <code>.gitignore</code> 文件，想沿用它的规则</td><td>Node.js 项目，跳过 <code>node_modules</code></td></tr><tr><td><strong>自定义规则</strong></td><td>临时设置过滤规则，不想修改 <code>.gitignore</code></td><td>排除 <code>logs/</code> 和 <code>*.zip</code></td></tr><tr><td><strong>两者同时使用</strong></td><td>既想遵守 <code>.gitignore</code>，又想额外排除某些内容</td><td>项目中排除 <code>node_modules</code> + 额外排除 <code>dist</code></td></tr></tbody></table><h3 id="视图控制-二次筛选" tabindex="-1">视图控制（二次筛选） <a class="header-anchor" href="#视图控制-二次筛选" aria-label="Permalink to &quot;视图控制（二次筛选）&quot;">​</a></h3><p>生成之后的<strong>实时调整</strong>功能，所有调整无需重新请求后端：</p><p><img src="" alt="TODO: 视图控制面板截图"></p><table tabindex="0"><thead><tr><th>控件</th><th>说明</th></tr></thead><tbody><tr><td><strong>显示深度</strong></td><td>拖动滑块控制树的展开深度，快速收起深层子目录</td></tr><tr><td><strong>包含路径</strong></td><td>只显示包含指定路径的分支（如输入 <code>src/components</code> 则只看该目录分支）</td></tr><tr><td><strong>排除内容</strong></td><td>排除名称中包含指定关键词的节点，多个关键词用逗号分隔（如 <code>node_modules,dist</code>）</td></tr><tr><td><strong>显示文件</strong></td><td>切换是否显示文件节点</td></tr><tr><td><strong>显示文件大小</strong></td><td>在文件旁显示友好的大小信息（如 <code>12.34 KB</code>）</td></tr><tr><td><strong>显示目录大小</strong></td><td>在目录旁显示该目录下所有文件的累计大小</td></tr><tr><td><strong>显示目录子项</strong></td><td>在目录旁显示子文件和子目录数量（如 <code>[5 files, 3 dirs]</code>）</td></tr></tbody></table><blockquote><p><strong>示例场景</strong>: 先对整个项目生成完整树结构，然后在视图控制中输入包含路径 <code>src</code>、排除 <code>test</code>，实时得到简洁的源码结构。</p></blockquote><h3 id="元数据输出" tabindex="-1">元数据输出 <a class="header-anchor" href="#元数据输出" aria-label="Permalink to &quot;元数据输出&quot;">​</a></h3><p>勾选 <strong>&quot;包含元数据&quot;</strong> 后，输出的目录树顶部会附加以下信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 目录树生成信息</span></span>
<span class="line"><span>- 生成时间: 2026-05-08 01:30:00</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 统计信息</span></span>
<span class="line"><span>- 总目录: 42</span></span>
<span class="line"><span>- 总文件: 156</span></span>
<span class="line"><span>- 过滤规则数: 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 生成配置</span></span>
<span class="line"><span>- 目标路径: /path/to/project</span></span>
<span class="line"><span>- 显示文件: 是</span></span>
<span class="line"><span>- 显示隐藏: 否</span></span>
<span class="line"><span>- 过滤模式: 使用 .gitignore</span></span>
<span class="line"><span>- 最大深度: 5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 目录结构</span></span>
<span class="line"><span>my-project/</span></span></code></pre></div><p>如果同时启用了 <strong>&quot;包含筛选信息&quot;</strong>，还会额外输出视图控制中的当前筛选状态（显示深度、包含/排除条件等），方便在导出或发送到聊天时保留完整的上下文。</p><h3 id="路径历史" tabindex="-1">路径历史 <a class="header-anchor" href="#路径历史" aria-label="Permalink to &quot;路径历史&quot;">​</a></h3><p>每次成功生成的目录路径会自动记录到历史列表中，方便快速切换回之前分析过的目录：</p><ul><li><strong>点击历史路径</strong> — 自动填入目标路径并生成</li><li><strong>移除单条历史</strong> — 删除不需要的历史记录</li><li><strong>清空历史</strong> — 一键清除所有历史记录</li></ul><h3 id="配置持久化" tabindex="-1">配置持久化 <a class="header-anchor" href="#配置持久化" aria-label="Permalink to &quot;配置持久化&quot;">​</a></h3><p>所有配置参数（包括最后一次生成的树结构）都会自动保存。下次打开工具时，会直接恢复上次的视图状态，无需重新生成。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="搭配视图控制做-分层分析" tabindex="-1">搭配视图控制做&quot;分层分析&quot; <a class="header-anchor" href="#搭配视图控制做-分层分析" aria-label="Permalink to &quot;搭配视图控制做&quot;分层分析&quot;&quot;">​</a></h3><p>对同一个大目录，通过不同的视图控制参数可以观察不同维度的结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 次: 目标路径 = D:/project</span></span>
<span class="line"><span>→ 视图控制：包含路径 = src，排除 = test</span></span>
<span class="line"><span>→ 获得源码结构，方便向 AI 介绍项目</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 次: 保持同一生成结果</span></span>
<span class="line"><span>→ 视图控制：包含路径 = docs，显示文件大小</span></span>
<span class="line"><span>→ 获得文档目录结构，了解哪些文档文件较大</span></span></code></pre></div><p>无需重新生成，切换视图片刻出结果。</p><h3 id="配合自定义规则做精确过滤" tabindex="-1">配合自定义规则做精确过滤 <a class="header-anchor" href="#配合自定义规则做精确过滤" aria-label="Permalink to &quot;配合自定义规则做精确过滤&quot;">​</a></h3><p>团队项目中有多个模块，只想看核心模块的结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>过滤模式: 自定义规则</span></span>
<span class="line"><span>自定义规则:</span></span>
<span class="line"><span>  # 排除所有测试文件</span></span>
<span class="line"><span>  __tests__</span></span>
<span class="line"><span>  *.test.*</span></span>
<span class="line"><span>  # 排除构建产物</span></span>
<span class="line"><span>  dist</span></span>
<span class="line"><span>  build</span></span>
<span class="line"><span>  coverage</span></span></code></pre></div><p>生成结果中会跳过这些目录和文件，树结构更聚焦。</p><h3 id="结合元数据输出做-code-review" tabindex="-1">结合元数据输出做 Code Review <a class="header-anchor" href="#结合元数据输出做-code-review" aria-label="Permalink to &quot;结合元数据输出做 Code Review&quot;">​</a></h3><p>生成目录树时开启元数据，然后将结果发送到 LLM 聊天：</p><ol><li>配置好参数后点击生成</li><li>勾选 <strong>&quot;包含元数据&quot;</strong> 和 <strong>&quot;包含筛选信息&quot;</strong></li><li>点击 <strong>&quot;发送到聊天&quot;</strong></li><li>在 LLM 聊天窗口中，AI 能基于完整的目录结构和元数据进行分析</li></ol><h3 id="使用深度限制控制输出长度" tabindex="-1">使用深度限制控制输出长度 <a class="header-anchor" href="#使用深度限制控制输出长度" aria-label="Permalink to &quot;使用深度限制控制输出长度&quot;">​</a></h3><p>对于层级很深的项目（如 <code>node_modules</code>），合理设置深度可以避免生成过长的输出：</p><table tabindex="0"><thead><tr><th>场景</th><th>推荐深度</th><th>说明</th></tr></thead><tbody><tr><td>项目概览</td><td><code>2</code></td><td>只看顶层模块</td></tr><tr><td>模块结构</td><td><code>3-4</code></td><td>看模块下的子目录</td></tr><tr><td>完整分析</td><td><code>5-8</code></td><td>覆盖大多数项目需求</td></tr><tr><td>无限制</td><td><code>0</code></td><td>全量输出（慎用，可能很长）</td></tr></tbody></table><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="生成速度慢怎么办" tabindex="-1">生成速度慢怎么办？ <a class="header-anchor" href="#生成速度慢怎么办" aria-label="Permalink to &quot;生成速度慢怎么办？&quot;">​</a></h3><p>目录遍历由 Rust 后端执行，通常非常快。如果感觉很慢，建议：</p><ul><li>检查是否开启了&quot;显示隐藏项目&quot;（会遍历更多文件）</li><li>降低&quot;最大深度&quot;值</li><li>使用过滤模式排除 <code>node_modules</code> 等大型目录</li></ul><h3 id="为什么某些目录或文件没有显示" tabindex="-1">为什么某些目录或文件没有显示？ <a class="header-anchor" href="#为什么某些目录或文件没有显示" aria-label="Permalink to &quot;为什么某些目录或文件没有显示？&quot;">​</a></h3><p>可能的原因：</p><ul><li><strong>过滤规则生效</strong> — 检查当前的过滤模式是否排除了该内容</li><li><strong>超出深度限制</strong> — 检查&quot;最大深度&quot;设置是否足够</li><li><strong>&quot;显示文件&quot;已关闭</strong> — 确认是否开启了文件显示</li><li><strong>&quot;显示隐藏项目&quot;已关闭</strong> — 隐藏文件（以 <code>.</code> 开头）默认不显示</li></ul><h3 id="视图控制和配置面板有什么区别" tabindex="-1">视图控制和配置面板有什么区别？ <a class="header-anchor" href="#视图控制和配置面板有什么区别" aria-label="Permalink to &quot;视图控制和配置面板有什么区别？&quot;">​</a></h3><p>两者有本质区别：</p><table tabindex="0"><thead><tr><th></th><th>配置面板</th><th>视图控制</th></tr></thead><tbody><tr><td><strong>时机</strong></td><td>生成之前设置</td><td>生成之后调整</td></tr><tr><td><strong>是否重新扫描</strong></td><td>✅ 需要重新生成</td><td>❌ 仅前端实时渲染</td></tr><tr><td><strong>适用场景</strong></td><td>改变过滤规则、深度等初始参数</td><td>快速折叠、按路径聚焦、排除关键词</td></tr></tbody></table><p><strong>最佳实践</strong>: 先用配置面板选好合适的过滤规则生成一次，然后通过视图控制做各种视角的微调，避免反复调用后端。</p><h3 id="自定义规则的语法是怎样的" tabindex="-1">自定义规则的语法是怎样的？ <a class="header-anchor" href="#自定义规则的语法是怎样的" aria-label="Permalink to &quot;自定义规则的语法是怎样的？&quot;">​</a></h3><p>支持标准的 <strong>glob</strong> 模式，每行一条规则，以 <code>#</code> 开头的行会被忽略：</p><div class="language-gitignore vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gitignore</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 排除 node_modules 目录</span></span>
<span class="line"><span>node_modules</span></span>
<span class="line"><span># 排除所有日志文件</span></span>
<span class="line"><span>*.log</span></span>
<span class="line"><span># 排除 dist 和 build 目录</span></span>
<span class="line"><span>dist</span></span>
<span class="line"><span>build</span></span>
<span class="line"><span># 排除隐藏目录</span></span>
<span class="line"><span>.*</span></span></code></pre></div><p>你可以直接参考 <code>.gitignore</code> 的语法规则来编写。</p><h3 id="发送到聊天会包含什么内容" tabindex="-1">发送到聊天会包含什么内容？ <a class="header-anchor" href="#发送到聊天会包含什么内容" aria-label="Permalink to &quot;发送到聊天会包含什么内容？&quot;">​</a></h3><p>发送到聊天的是<strong>编辑器当前显示的内容</strong>，包括：</p><ul><li>如果开启了&quot;包含元数据&quot;，会一并发送元数据信息</li><li>当前视图控制下的树结构（二次筛选后的结果）</li><li>如果你在编辑器中手动修改了任何内容，这些修改也会被发送</li></ul><p>这让你可以精确定制发送给 LLM 的内容，去掉不必要的信息。</p>`,72)])])}const u=a(e,[["render",d]]);export{g as __pageData,u as default};
